-/// Print human-readable error to stderr.
-fn print_human_error(error: &ExplainError) {
-    eprintln!();
-    eprintln!("\x1b[31mError: {}\x1b[0m", error.code);
-    eprintln!("{}", error.message);
-
-    if !error.hints.is_empty() {
-        eprintln!();
-        eprintln!("Hints:");
-        for hint in &error.hints {
-            eprintln!("  - {hint}");
-        }
-    }
-    eprintln!();
-}
