-/// Truncate a hex ID for display (show first 8 and last 8 chars).
-fn truncate_id(id: &str) -> String {
-    if id.len() <= 20 {
-        id.to_string()
-    } else {
-        format!("{}...{}", &id[..8], &id[id.len() - 8..])
-    }
-}
