-
-    // Create object ID key from demo key (in reality, this comes from zone config)
-    let object_id_key = ObjectIdKey::from_bytes(
-        demo_keys.signing_key.to_bytes()[..32]
-            .try_into()
-            .unwrap_or([0u8; 32]),
